$targets = @(
    "$env:USERPROFILE\Desktop",
    "$env:USERPROFILE\Downloads",
    "$env:USERPROFILE\Documents",
    "$env:USERPROFILE\Pictures",
    "$env:USERPROFILE\Videos",
    "$env:USERPROFILE\Music",
    "$env:USERPROFILE\source",
    "C:\Users\25789"
)

$results = foreach ($dir in $targets) {
    if (Test-Path $dir) {
        Get-ChildItem $dir -File -Recurse -ErrorAction SilentlyContinue `
        | Where-Object { $_.Length -gt 0 } `
        | Group-Object @{e={$_.Name.ToLower() + "|" + $_.Length}} `
        | Where-Object Count -gt 1
    }
}

$results | ForEach-Object {
    $group = $_.Group
    $name = $group[0].Name
    Write-Host "`n=== 重复: $($group[0].Name.Split('|')[0]) ($( '{0:N0}' -f ($group[0].Length / 1KB)) KB) ====="
    $group | ForEach-Object { Write-Host "  $($_.FullName)  [$($_.LastWriteTime.ToString('yyyy-MM-dd HH:mm'))]" }
} | Out-String -Width 200

if (-not $results) { Write-Host "未找到重复文件" }
